<?php
$pageTitle='Create Job Card';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('job_cards');
$pdo=getDB();
$scopeOptions=scopeSelectOptions($pdo);
$scope=operationalScope($pdo);
$customers=$pdo->query('SELECT id,customer_code,company_name,contact_name,phone FROM '.table('customers').' WHERE status="active" ORDER BY company_name,contact_name ASC LIMIT 400')->fetchAll();
$users=$pdo->query('SELECT id,email,first_name,last_name FROM '.table('users').' WHERE status="active" AND (can_login_erp=1 OR role="admin") ORDER BY first_name,email ASC LIMIT 300')->fetchAll();
$costCenters=$pdo->query('SELECT id,cost_center_code,cost_center_name FROM '.table('cost_centers').' WHERE status="active" ORDER BY cost_center_code ASC')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  $scope=['company_id'=>(int)($_POST['company_id']??$scope['company_id']),'branch_id'=>(int)($_POST['branch_id']??$scope['branch_id']),'warehouse_id'=>(int)($_POST['warehouse_id']??$scope['warehouse_id']),'location_id'=>(int)setting('default_location_id','0')];
  $pdo->beginTransaction();
  try{
    enforceScopeAllowed($pdo,$scope['company_id'],$scope['branch_id'],$scope['warehouse_id'],true);
    $customerId=(int)($_POST['customer_id']??0)?:null;$customerName=trim((string)($_POST['customer_name']??''));$customerPhone=trim((string)($_POST['customer_phone']??''));
    if($customerId){$c=$pdo->prepare('SELECT * FROM '.table('customers').' WHERE id=? LIMIT 1');$c->execute([$customerId]);$customer=$c->fetch();if($customer){$customerName=trim(($customer['company_name']?:'').' '.($customer['contact_name']?:''));$customerPhone=(string)($customer['phone']??$customerPhone);}}
    if($customerName===''){throw new RuntimeException('Customer name is required.');}
    $number=nextScopedDocumentNumber($pdo,'job_card','JC',$scope);
    $stmt=$pdo->prepare('INSERT INTO '.table('job_cards').' (company_id,branch_id,warehouse_id,cost_center_id,job_card_number,customer_id,customer_name,customer_phone,asset_type,vehicle_make,vehicle_model,vehicle_year,vin,plate_number,odometer,service_advisor_user_id,technician_user_id,status,priority,opened_at,complaint,diagnosis,recommendation,notes) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,"draft",?,NOW(),?,?,?,?)');
    $stmt->execute([$scope['company_id']?:null,$scope['branch_id']?:null,$scope['warehouse_id']?:null,(int)($_POST['cost_center_id']??0)?:null,$number,$customerId,$customerName,$customerPhone,trim((string)($_POST['asset_type']??'vehicle')),trim((string)($_POST['vehicle_make']??'')),trim((string)($_POST['vehicle_model']??'')),trim((string)($_POST['vehicle_year']??'')),trim((string)($_POST['vin']??'')),trim((string)($_POST['plate_number']??'')),trim((string)($_POST['odometer']??'')),(int)($_POST['service_advisor_user_id']??0)?:null,(int)($_POST['technician_user_id']??0)?:null,trim((string)($_POST['priority']??'normal')),trim((string)($_POST['complaint']??'')),trim((string)($_POST['diagnosis']??'')),trim((string)($_POST['recommendation']??'')),trim((string)($_POST['notes']??''))]);
    $id=(int)$pdo->lastInsertId();
    logActivity($pdo,'Service','job_card_created','Job card '.$number.' created.','job_card',$id);
    $pdo->commit();flash('success','Job card created.');redirect(ADMIN_URL.'/erp/view-job-card.php?id='.$id);
  }catch(Throwable $e){if($pdo->inTransaction()){$pdo->rollBack();}flash('error',$e->getMessage());redirect(ADMIN_URL.'/erp/create-job-card.php');}
}
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Workshop Intake</div><h2 class="h4 mb-1">Create Job Card</h2><p class="text-secondary mb-0">Open a workshop or service order with customer, asset, complaint, advisor, technician, and cost center.</p></div><a class="btn btn-outline-secondary" href="<?php echo esc(ADMIN_URL); ?>/erp/job-cards.php">Back</a></div>
<form method="post" class="row g-4"><div class="col-xl-4"><div class="card-admin p-4"><h2 class="h5 mb-3">Scope & Assignment</h2><div class="row g-3"><div class="col-12"><label class="form-label">Company</label><select class="form-select" name="company_id"><?php foreach($scopeOptions['companies'] as $company): ?><option value="<?php echo (int)$company['id']; ?>" <?php echo (int)$company['id']===(int)$scope['company_id']?'selected':''; ?>><?php echo esc($company['company_code'].' · '.$company['company_name']); ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label">Branch</label><select class="form-select" name="branch_id"><?php foreach($scopeOptions['branches'] as $branch): ?><option value="<?php echo (int)$branch['id']; ?>" <?php echo (int)$branch['id']===(int)$scope['branch_id']?'selected':''; ?>><?php echo esc($branch['branch_code'].' · '.$branch['branch_name']); ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label">Warehouse</label><select class="form-select" name="warehouse_id"><?php foreach($scopeOptions['warehouses'] as $warehouse): ?><option value="<?php echo (int)$warehouse['id']; ?>" <?php echo (int)$warehouse['id']===(int)$scope['warehouse_id']?'selected':''; ?>><?php echo esc($warehouse['warehouse_code'].' · '.$warehouse['warehouse_name']); ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label">Cost Center</label><select class="form-select" name="cost_center_id"><option value="0">No cost center</option><?php foreach($costCenters as $cc): ?><option value="<?php echo (int)$cc['id']; ?>"><?php echo esc($cc['cost_center_code'].' · '.$cc['cost_center_name']); ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label">Technician</label><select class="form-select" name="technician_user_id"><option value="0">Unassigned</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc(trim(($u['first_name']?:'').' '.($u['last_name']?:'')).' · '.$u['email']); ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label">Service Advisor</label><select class="form-select" name="service_advisor_user_id"><option value="0">None</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc(trim(($u['first_name']?:'').' '.($u['last_name']?:'')).' · '.$u['email']); ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label">Priority</label><select class="form-select" name="priority"><option value="normal">Normal</option><option value="urgent">Urgent</option><option value="vip">VIP</option></select></div></div></div></div><div class="col-xl-8"><div class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Customer & Asset</h2><div class="row g-3"><div class="col-md-6"><label class="form-label">Existing Customer</label><select class="form-select" name="customer_id"><option value="0">Manual customer</option><?php foreach($customers as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['customer_code'].' · '.trim(($c['company_name']?:'').' '.($c['contact_name']?:''))); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">Manual Customer Name</label><input class="form-control" name="customer_name"></div><div class="col-md-4"><label class="form-label">Phone</label><input class="form-control" name="customer_phone"></div><div class="col-md-4"><label class="form-label">Make</label><input class="form-control" name="vehicle_make"></div><div class="col-md-4"><label class="form-label">Model</label><input class="form-control" name="vehicle_model"></div><div class="col-md-3"><label class="form-label">Year</label><input class="form-control" name="vehicle_year"></div><div class="col-md-3"><label class="form-label">Plate</label><input class="form-control" name="plate_number"></div><div class="col-md-3"><label class="form-label">VIN</label><input class="form-control" name="vin"></div><div class="col-md-3"><label class="form-label">Odometer</label><input class="form-control" name="odometer"></div></div></div><div class="card-admin p-4"><h2 class="h5 mb-3">Service Notes</h2><div class="row g-3"><div class="col-12"><label class="form-label">Complaint</label><textarea class="form-control" rows="3" name="complaint"></textarea></div><div class="col-md-6"><label class="form-label">Diagnosis</label><textarea class="form-control" rows="3" name="diagnosis"></textarea></div><div class="col-md-6"><label class="form-label">Recommendation</label><textarea class="form-control" rows="3" name="recommendation"></textarea></div><div class="col-12"><label class="form-label">Internal Notes</label><textarea class="form-control" rows="2" name="notes"></textarea></div></div><button class="btn btn-brand mt-3">Create Job Card</button></div></div></form>
<?php include dirname(__DIR__).'/footer.php'; ?>